const validators = cluster.getAgentsByRole('validator');
const lastImpl = ledger.findLast({ topic: 'IMPLEMENTATION_READY' });
if (!lastImpl) return false;
const validatorIds = new Set(validators.map(v => v.id));
const results = ledger.query({ topic: 'VALIDATION_RESULT', since: lastImpl.timestamp });
const latestByValidator = new Map();
for (const msg of results) {
  if (!validatorIds.has(msg.sender)) continue;
  latestByValidator.set(msg.sender, msg);
}
if (latestByValidator.size < validators.length) return false;
for (const [id, msg] of latestByValidator) {
  const approved = msg?.content?.data?.approved;
  if (approved === false || approved === 'false') return true;
}
return false;

